import json, re, math
from dataclasses import dataclass

NUM_RE = re.compile(r"-?\d+(?:\.\d+)?")

def extract_final_number(text: str):
    m = re.search(r"FINAL\s*:\s*([-+]?\d+(?:\.\d+)?)", text)
    if m:
        return float(m.group(1))
    nums = NUM_RE.findall(text)
    return float(nums[-1]) if nums else None

def safe_float(x):
    try:
        return float(x)
    except Exception:
        return None

def approx_equal(a, b, tol=1e-6):
    if a is None or b is None:
        return False
    return abs(a - b) <= tol * max(1.0, abs(a), abs(b))

@dataclass
class CheckResult:
    ok: bool
    note: str

def check_commitment(commit_json: dict):
    # Minimal schema
    for k in ["variables", "constraints", "plan", "invariants"]:
        if k not in commit_json:
            return CheckResult(False, f"Missing key: {k}")
    if not isinstance(commit_json["invariants"], list) or len(commit_json["invariants"]) == 0:
        return CheckResult(False, "No invariants")
    return CheckResult(True, "ok")

def eval_invariant(inv: str, env: dict):
    """Supports forms like 'a+b==c', 'x<=y', 'x==10'."""
    inv = inv.strip()
    # Replace '^' with '**'
    inv = inv.replace('^', '**')
    # Allow common math functions
    safe_env = {"__builtins__": {}, "math": math}
    safe_env.update(env)
    try:
        return bool(eval(inv, safe_env, {}))
    except Exception:
        return None

def check_solution(commit_json: dict, sol_text: str):
    # Expect an evidence JSON blob optionally
    final = extract_final_number(sol_text)
    if final is None:
        return CheckResult(False, "No FINAL number")

    # Build environment from declared variables if they have values
    env = {}
    for name, val in (commit_json.get("variables") or {}).items():
        f = safe_float(val)
        if f is not None:
            env[name] = f
    env["FINAL"] = final

    # Check invariants
    invs = commit_json.get("invariants") or []
    failures = []
    for inv in invs:
        res = eval_invariant(inv, env)
        if res is not True:
            failures.append(inv)
    if failures:
        return CheckResult(False, f"Invariant failed/unevaluable: {failures[0]}")

    return CheckResult(True, "ok")

COMMIT_PROMPT = """You will NOT solve yet. First, extract a compact commitment JSON.
Return ONLY valid JSON with keys:
variables: object of variable_name -> value_or_null (use null if unknown)
constraints: list of short constraint strings from the problem
plan: list of 2-4 short steps
invariants: list of 1-3 checkable statements using variables and FINAL (e.g., 'a+b==FINAL', 'x<=FINAL').

Problem: {q}
"""

SOLVE_PROMPT = """Now solve concisely.
You MUST output:
1) FINAL: <number>
2) A short line 'INVARIANTS_USED:' mentioning each invariant index you satisfied.

Problem: {q}
Commitments JSON:
{cj}
"""

REPAIR_PROMPT = """Your previous answer failed this check: {note}
Revise EITHER (a) the FINAL answer OR (b) the commitments/invariants, but you must explicitly state what changed.
Return:
- Updated commitments JSON (ONLY JSON)
- Then a revised solution with FINAL.

Problem: {q}
Old commitments:
{cj}
Old solution:
{sol}
"""

def c3ot_solve(q, llm, max_repair=1):
    cj_text = llm(COMMIT_PROMPT.format(q=q))
    try:
        cj = json.loads(cj_text)
    except Exception:
        cj = {"variables": {}, "constraints": [], "plan": [], "invariants": []}

    cr = check_commitment(cj)
    sol = llm(SOLVE_PROMPT.format(q=q, cj=json.dumps(cj)))

    sr = check_solution(cj, sol) if cr.ok else CheckResult(False, "Bad commitment JSON")

    if sr.ok or max_repair <= 0:
        return sol, cj, sr

    # One repair round
    rep = llm(REPAIR_PROMPT.format(q=q, cj=json.dumps(cj), sol=sol, note=sr.note))

    # Split updated JSON from solution: first JSON object up to matching brace
    new_cj = cj
    new_sol = rep
    try:
        # naive: take first {...}
        start = rep.find('{')
        end = rep.rfind('}')
        if start != -1 and end != -1 and end > start:
            new_cj = json.loads(rep[start:end+1])
            new_sol = rep[end+1:]
    except Exception:
        pass

    sr2 = check_solution(new_cj, new_sol)
    return new_sol, new_cj, sr2

